const incoming = $input.first()?.json ?? {};

const parseMaybeJson = (value) => {
  if (typeof value !== 'string') {
    return value;
  }
  try {
    return JSON.parse(value);
  } catch {
    return value;
  }
};

const root = parseMaybeJson(incoming);
const bodyRaw = parseMaybeJson(root?.body ?? root?.payload ?? root);
const body = (bodyRaw && typeof bodyRaw === 'object') ? bodyRaw : {};

const query = String(
  body.query
  ?? body.topic
  ?? root?.query
  ?? root?.topic
  ?? '한국 AI 트렌드'
);
const collectedAt = String(
  body.collected_at
  ?? body.collectedAt
  ?? root?.collected_at
  ?? root?.collectedAt
  ?? new Date().toISOString()
);

const candidateArrays = [
  body.results,
  body.items,
  body?.data?.results,
  body?.data?.items,
  root?.results,
  root?.items,
  root?.data?.results,
  root?.data?.items,
];
const sourceItems = candidateArrays.find((entry) => Array.isArray(entry)) ?? [];

const INJECTION_PATTERNS = [
  /ignore\s+(all\s+)?(previous|above|system|developer)\s+instructions?/gi,
  /system\s+prompt/gi,
  /developer\s+message/gi,
  /```[\s\S]*?```/g,
  /<script[\s\S]*?>[\s\S]*?<\/script>/gi,
  /javascript:/gi,
  /\b(bash|sudo|rm\s+-rf|curl\s+https?:\/\/|wget\s+https?:\/\/)\b/gi,
];

const securityStats = {
  input_count: sourceItems.length,
  kept_count: 0,
  dropped_count: 0,
  dropped_unsafe_url: 0,
  prompt_like_removed: 0,
  source_provider: 'external_webhook',
};

const compact = (value) => String(value ?? '')
  .replace(/[\u0000-\u001F\u007F]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const sanitizeText = (value, maxLen) => {
  let text = String(value ?? '');
  for (const pattern of INJECTION_PATTERNS) {
    const before = text;
    text = text.replace(pattern, ' ');
    if (before !== text) {
      securityStats.prompt_like_removed += 1;
    }
  }
  const normalized = compact(text);
  return normalized.length > maxLen ? `${normalized.slice(0, maxLen - 1).trimEnd()}…` : normalized;
};

const isSafeUrl = (value) => {
  const raw = String(value ?? '').trim();
  if (!/^https?:\/\//i.test(raw)) {
    return false;
  }
  const withoutScheme = raw.replace(/^https?:\/\//i, '');
  const authority = withoutScheme.split('/')[0] || '';
  const hostPort = authority.includes('@') ? authority.split('@').pop() : authority;
  const host = String((hostPort || '').split(':')[0] || '').toLowerCase();
  if (!host || host === 'localhost' || host.endsWith('.local')) {
    return false;
  }
  if (/^127\./.test(host) || /^10\./.test(host) || /^192\.168\./.test(host)) {
    return false;
  }
  if (/^172\.(1[6-9]|2\d|3[0-1])\./.test(host)) {
    return false;
  }
  if (/^169\.254\./.test(host) || host === '::1') {
    return false;
  }
  return true;
};

const classifyBucket = (title, snippet, explicitBucket) => {
  const bucket = String(explicitBucket ?? '').trim().toUpperCase();
  if (['HOT', 'INSIGHT', 'MONITOR'].includes(bucket)) {
    return bucket;
  }
  const lowered = `${title} ${snippet}`.toLowerCase();
  if (lowered.includes('launch') || lowered.includes('release') || lowered.includes('breaking') || lowered.includes('급등')) {
    return 'HOT';
  }
  if (lowered.includes('analysis') || lowered.includes('report') || lowered.includes('전망') || lowered.includes('인사이트')) {
    return 'INSIGHT';
  }
  return 'MONITOR';
};

const normalizedItems = sourceItems
  .map((entry, index) => {
    const title = sanitizeText(entry?.title ?? `untitled-${index + 1}`, 180);
    const url = String(entry?.url ?? '').trim();
    const snippet = sanitizeText(entry?.snippet ?? entry?.content ?? '', 400);

    if (!title || !url || !isSafeUrl(url)) {
      securityStats.dropped_count += 1;
      if (url && !isSafeUrl(url)) {
        securityStats.dropped_unsafe_url += 1;
      }
      return null;
    }

    return {
      title,
      url,
      snippet: snippet || '요약 정보 없음',
      bucket: classifyBucket(title, snippet, entry?.bucket),
    };
  })
  .filter((item) => item)
  .slice(0, 30);

securityStats.kept_count = normalizedItems.length;

return [
  {
    json: {
      query,
      collected_at: collectedAt,
      items: normalizedItems,
      security_stats: securityStats,
    },
  },
];

const data = $input.first()?.json ?? {};
const query = data.query ?? '한국 AI 트렌드';
const collectedAt = data.collected_at ?? new Date().toISOString();
const items = Array.isArray(data.items) ? data.items : [];
const securityStats = data.security_stats ?? {};

const buckets = {
  HOT: [],
  INSIGHT: [],
  MONITOR: [],
};
for (const item of items) {
  const key = ['HOT', 'INSIGHT', 'MONITOR'].includes(item.bucket) ? item.bucket : 'MONITOR';
  buckets[key].push(item);
}

const toLines = (bucketItems) => {
  if (!bucketItems.length) {
    return ['- 없음'];
  }
  return bucketItems.map((item, index) => {
    const title = item.title || `Item ${index + 1}`;
    const url = item.url ? ` (${item.url})` : '';
    const snippet = item.snippet ? `\n  - 요약: ${item.snippet}` : '';
    return `- ${title}${url}${snippet}`;
  });
};

const markdown = [
  '# Hermes Daily Briefing',
  '',
  `- generated_at: ${new Date().toISOString()}`,
  `- collected_at: ${collectedAt}`,
  `- query: ${query}`,
  '',
  '## HOT',
  ...toLines(buckets.HOT),
  '',
  '## INSIGHT',
  ...toLines(buckets.INSIGHT),
  '',
  '## MONITOR',
  ...toLines(buckets.MONITOR),
  '',
  '## Safety',
  `- source_provider: ${securityStats.source_provider ?? 'unknown'}`,
  `- input_count: ${securityStats.input_count ?? 0}`,
  `- kept_count: ${securityStats.kept_count ?? 0}`,
  `- dropped_count: ${securityStats.dropped_count ?? 0}`,
  `- dropped_unsafe_url: ${securityStats.dropped_unsafe_url ?? 0}`,
  `- prompt_like_removed: ${securityStats.prompt_like_removed ?? 0}`,
  '',
  '## 액션 제안',
  '- Minerva: HOT 항목 우선순위 반영 검토',
  '- Clio: INSIGHT 항목 문서화/지식베이스 반영',
].join('\n');

const summary = {
  total: items.length,
  hot: buckets.HOT.length,
  insight: buckets.INSIGHT.length,
  monitor: buckets.MONITOR.length,
};

return [
  {
    json: {
      query,
      collected_at: collectedAt,
      generated_at: new Date().toISOString(),
      items,
      has_items: items.length > 0,
      bucket_counts: summary,
      briefing_markdown: markdown,
      summary: `total=${summary.total}, hot=${summary.hot}, insight=${summary.insight}, monitor=${summary.monitor}`,
      security_stats: securityStats,
    },
  },
];

const current = $input.first()?.json ?? {};
const staticData = $getWorkflowStaticData('global');

const makeFingerprint = (value) => {
  const str = String(value ?? '');
  let hash = 0;
  for (let i = 0; i < str.length; i += 1) {
    hash = (hash * 31 + str.charCodeAt(i)) >>> 0;
  }
  return hash.toString(16);
};

const dateKey = new Date().toISOString().slice(0, 10);
const fingerprintSource = `${current.query}\n${(current.items ?? []).map((item) => `${item.title}|${item.url}|${item.snippet}`).join('\n')}`;
const fingerprint = makeFingerprint(fingerprintSource);

const hasItems = Boolean(current.has_items);
const duplicate = hasItems && staticData.last_fingerprint === fingerprint && staticData.last_date === dateKey;

let skipped = false;
let skipReason = null;

if (!hasItems) {
  skipped = true;
  skipReason = 'no_results';
} else if (duplicate) {
  skipped = true;
  skipReason = 'duplicate_briefing';
} else {
  staticData.last_fingerprint = fingerprint;
  staticData.last_date = dateKey;
  staticData.last_generated_at = new Date().toISOString();
}

return [
  {
    json: {
      ...current,
      fingerprint,
      skipped,
      skip_reason: skipReason,
      duplicate,
    },
  },
];

const data = $input.first()?.json ?? {};
const buckets = data.bucket_counts ?? { total: 0, hot: 0, insight: 0, monitor: 0 };
const orchestrationUrl = $env.ORCHESTRATION_EVENT_URL || 'http://frontend:3000/api/orchestration/events';

const sourceRefs = Array.isArray(data.items)
  ? data.items
      .filter((item) => item?.title && item?.url)
      .slice(0, 6)
      .map((item) => ({
        title: item.title,
        url: item.url,
        snippet: item.snippet ?? undefined,
        publisher: item.publisher ?? undefined,
        category: item.category ?? undefined,
        priorityTier: item.priorityTier ?? data.priority_tier ?? undefined,
        domain: item.domain ?? undefined,
      }))
  : [];

const orchestration = {
  attempted: false,
  url: orchestrationUrl,
  status: null,
  ok: null,
  decision: null,
  detail: null,
};

if (!data.skipped) {
  const priority = Number(buckets.hot ?? 0) > 0 ? 'high' : 'normal';
  const confidence = Number(buckets.hot ?? 0) > 0 ? 0.84 : 0.72;
  const tierTag = String(data.priority_tier ?? 'P2').toLowerCase();
  const topicKey = String(data.query ?? 'hermes-briefing')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 64) || 'hermes-briefing';

  const payload = {
    agentId: 'hermes',
    topicKey,
    title: `Hermes Briefing: ${String(data.query ?? '').slice(0, 72)}`,
    summary: data.summary ?? 'Hermes briefing generated',
    priority,
    confidence,
    tags: ['hermes', 'trend', 'briefing', `tier:${tierTag}`],
    sourceRefs,
    insightHint: '카테고리 간 연결고리와 파급 영향을 Minerva 관점으로 점검하세요.',
    payload: {
      workflow: 'hermes-daily-briefing',
      fingerprint: data.fingerprint ?? null,
      bucket_counts: buckets,
      collected_at: data.collected_at ?? null,
      generated_at: data.generated_at ?? null,
      priority_tier: data.priority_tier ?? null,
      cadence: data.cadence ?? null,
      schedule_slot: data.schedule_slot ?? null,
      source_plan: data.source_plan ?? null,
    },
  };

  orchestration.attempted = true;
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: orchestrationUrl,
      body: payload,
      json: true,
      timeout: 5000,
      returnFullResponse: true,
    });
    orchestration.status = Number(response?.statusCode ?? 0) || null;
    orchestration.ok = orchestration.status !== null && orchestration.status >= 200 && orchestration.status < 300;
    const responseBody = response?.body ?? null;
    orchestration.decision = responseBody?.decision ?? null;
    orchestration.detail = responseBody;
  } catch (error) {
    orchestration.ok = false;
    orchestration.detail = error?.message ?? 'orchestration_publish_failed';
  }
}

return [
  {
    json: {
      ok: true,
      source: 'n8n-local',
      workflow: 'hermes-daily-briefing',
      skipped: Boolean(data.skipped),
      reason: data.skip_reason ?? null,
      duplicate: Boolean(data.duplicate),
      fingerprint: data.fingerprint ?? null,
      summary: data.summary ?? null,
      bucket_counts: buckets,
      briefing_markdown: data.skipped ? null : (data.briefing_markdown ?? null),
      generated_at: data.generated_at ?? new Date().toISOString(),
      collected_at: data.collected_at ?? null,
      priority_tier: data.priority_tier ?? null,
      cadence: data.cadence ?? null,
      schedule_slot: data.schedule_slot ?? null,
      source_plan: data.source_plan ?? null,
      security_stats: data.security_stats ?? null,
      orchestration,
    },
  },
];

const collectedAt = new Date().toISOString();
const dateKey = collectedAt.slice(0, 10);
const tier = 'P0';
const cadence = 'daily';
const scheduleSlot = 'p0_daily_kst_0900';
const queryBase = "P0 Daily Signals: KR Super App + Global AI/Core Infra";
const tierDomains = ["toss.tech", "d2.naver.com", "tech.kakao.com", "news.hada.io", "openai.com", "anthropic.com", "blog.cloudflare.com", "aws.amazon.com", "news.ycombinator.com"];
const sourceMeta = {"toss.tech": {"publisher": "Toss Tech", "category": "kr_super_app"}, "d2.naver.com": {"publisher": "Naver D2", "category": "kr_engineering_core"}, "tech.kakao.com": {"publisher": "Kakao Tech", "category": "kr_engineering_core"}, "news.hada.io": {"publisher": "GeekNews", "category": "kr_aggregator"}, "openai.com": {"publisher": "OpenAI News", "category": "global_ai"}, "anthropic.com": {"publisher": "Anthropic News", "category": "global_ai"}, "blog.cloudflare.com": {"publisher": "Cloudflare Blog", "category": "global_bigtech"}, "aws.amazon.com": {"publisher": "AWS News Blog", "category": "global_bigtech"}, "news.ycombinator.com": {"publisher": "Hacker News", "category": "global_aggregator"}, "techblog.woowahan.com": {"publisher": "Woowahan Tech", "category": "kr_super_app"}, "daangn.com": {"publisher": "Karrot Tech", "category": "kr_super_app"}, "karrot.com": {"publisher": "Karrot Tech", "category": "kr_super_app"}, "blog.myrealtrip.com": {"publisher": "MyRealTrip Tech", "category": "kr_mobility"}, "tech.socarcorp.kr": {"publisher": "Socar Tech", "category": "kr_mobility"}, "upstage.ai": {"publisher": "Upstage", "category": "kr_ai_growth"}, "blog.ab180.co": {"publisher": "AB180", "category": "kr_ai_growth"}, "netflixtechblog.com": {"publisher": "Netflix TechBlog", "category": "global_bigtech"}, "airbnb.tech": {"publisher": "Airbnb Engineering", "category": "global_bigtech"}, "uber.com": {"publisher": "Uber Engineering", "category": "global_bigtech"}, "huggingface.co": {"publisher": "Hugging Face Blog", "category": "global_ai"}, "deepmind.google": {"publisher": "Google DeepMind Blog", "category": "global_ai"}, "stratechery.com": {"publisher": "Stratechery", "category": "global_strategy"}, "lennysnewsletter.com": {"publisher": "Lenny's Newsletter", "category": "global_strategy"}, "engineering.linecorp.com": {"publisher": "LINE Engineering", "category": "kr_super_app"}, "yanolja.github.io": {"publisher": "Yanolja Tech", "category": "kr_mobility"}, "tmapmobility.com": {"publisher": "Tmap Mobility Tech", "category": "kr_mobility"}, "hyperconnect.com": {"publisher": "Hyperconnect", "category": "kr_ai_growth"}, "stripe.com": {"publisher": "Stripe Blog", "category": "global_bigtech"}, "reforge.com": {"publisher": "Reforge Blog", "category": "global_strategy"}, "infoq.com": {"publisher": "InfoQ", "category": "global_aggregator"}, "techcrunch.com": {"publisher": "TechCrunch", "category": "global_aggregator"}};

const provider = String($env.HERMES_SEARCH_PROVIDER || 'auto').trim().toLowerCase() || 'auto';
const tavilyKey = String($env.TAVILY_API_KEY || '').trim();
const tavilyBase = String($env.TAVILY_API_BASE || 'https://api.tavily.com').replace(/\/+$/, '');
const tavilyDepth = String($env.TAVILY_SEARCH_DEPTH || 'basic').trim() || 'basic';
const useTavily = (provider === 'tavily' || provider === 'auto') && tavilyKey.length > 0;

const INJECTION_PATTERNS = [
  /ignore\s+(all\s+)?(previous|above|system|developer)\s+instructions?/gi,
  /system\s+prompt/gi,
  /developer\s+message/gi,
  /```[\s\S]*?```/g,
  /<script[\s\S]*?>[\s\S]*?<\/script>/gi,
  /javascript:/gi,
  /\b(bash|sudo|rm\s+-rf|curl\s+https?:\/\/|wget\s+https?:\/\/)\b/gi,
];

const securityStats = {
  input_count: 0,
  kept_count: 0,
  dropped_count: 0,
  dropped_unsafe_url: 0,
  prompt_like_removed: 0,
  source_provider: useTavily ? 'tavily' : 'hn_algolia',
  tier,
  cadence,
};

const compact = (value) => String(value ?? '')
  .replace(/[\u0000-\u001F\u007F]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const sanitizeText = (value, maxLen) => {
  let text = String(value ?? '');
  for (const pattern of INJECTION_PATTERNS) {
    const before = text;
    text = text.replace(pattern, ' ');
    if (before !== text) {
      securityStats.prompt_like_removed += 1;
    }
  }
  const normalized = compact(text);
  return normalized.length > maxLen ? `${normalized.slice(0, maxLen - 1).trimEnd()}…` : normalized;
};

const isSafeUrl = (value) => {
  const raw = String(value ?? '').trim();
  if (!/^https?:\/\//i.test(raw)) {
    return false;
  }
  const withoutScheme = raw.replace(/^https?:\/\//i, '');
  const authority = withoutScheme.split('/')[0] || '';
  const hostPort = authority.includes('@') ? authority.split('@').pop() : authority;
  const host = String((hostPort || '').split(':')[0] || '').toLowerCase();
  if (!host || host === 'localhost' || host.endsWith('.local')) {
    return false;
  }
  if (/^127\./.test(host) || /^10\./.test(host) || /^192\.168\./.test(host)) {
    return false;
  }
  if (/^172\.(1[6-9]|2\d|3[0-1])\./.test(host)) {
    return false;
  }
  if (/^169\.254\./.test(host) || host === '::1') {
    return false;
  }
  return true;
};

const hostFromUrl = (value) => {
  try {
    return new URL(String(value ?? '')).hostname.trim().toLowerCase();
  } catch {
    return '';
  }
};

const inferMeta = (url) => {
  const host = hostFromUrl(url);
  if (!host) {
    return { domain: '', category: 'uncategorized', publisher: 'unknown' };
  }
  for (const [domain, meta] of Object.entries(sourceMeta)) {
    if (host === domain || host.endsWith(`.${domain}`)) {
      return { domain: host, category: meta.category, publisher: meta.publisher };
    }
  }
  return { domain: host, category: 'uncategorized', publisher: host };
};

const classifyBucket = (title, snippet) => {
  const lowered = `${title} ${snippet}`.toLowerCase();
  if (lowered.includes('launch') || lowered.includes('release') || lowered.includes('breaking') || lowered.includes('급등')) {
    return 'HOT';
  }
  if (lowered.includes('analysis') || lowered.includes('report') || lowered.includes('outlook') || lowered.includes('전망')) {
    return 'INSIGHT';
  }
  return 'MONITOR';
};

const sanitizeCandidate = (entry, fallbackTitle) => {
  const title = sanitizeText(entry?.title ?? fallbackTitle, 180);
  const url = String(entry?.url ?? '').trim();
  const snippet = sanitizeText(entry?.snippet ?? entry?.content ?? '', 400);

  if (!title || !url || !isSafeUrl(url)) {
    securityStats.dropped_count += 1;
    if (url && !isSafeUrl(url)) {
      securityStats.dropped_unsafe_url += 1;
    }
    return null;
  }

  const meta = inferMeta(url);
  return {
    title,
    url,
    snippet: snippet || '요약 정보 없음',
    bucket: classifyBucket(title, snippet),
    publisher: entry?.publisher ? sanitizeText(entry.publisher, 80) : meta.publisher,
    domain: meta.domain,
    category: entry?.category ? sanitizeText(entry.category, 48) : meta.category,
    priorityTier: tier,
  };
};

const query = `${queryBase} (${dateKey})`;
let rawItems = [];
try {
  if (useTavily) {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: `${tavilyBase}/search`,
      body: {
        api_key: tavilyKey,
        query,
        search_depth: tavilyDepth,
        max_results: 12,
        include_domains: tierDomains,
        include_answer: false,
        include_raw_content: false,
      },
      json: true,
      timeout: 9000,
    });
    const results = Array.isArray(response?.results) ? response.results : [];
    rawItems = results.map((entry, idx) => ({
      title: String(entry?.title ?? `tavily-item-${idx + 1}`).trim(),
      url: String(entry?.url ?? '').trim(),
      snippet: String(entry?.content ?? entry?.snippet ?? '').trim(),
    }));
  } else {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://hn.algolia.com/api/v1/search',
      qs: {
        query: `${queryBase} ${tierDomains.slice(0, 3).join(' ')}`,
        tags: 'story',
        hitsPerPage: 12,
      },
      json: true,
      timeout: 7000,
    });
    const hits = Array.isArray(response?.hits) ? response.hits : [];
    rawItems = hits.map((hit, idx) => ({
      title: String(hit?.title || hit?.story_title || `hn-story-${idx + 1}`).trim(),
      url: String(hit?.url || hit?.story_url || '').trim(),
      snippet: String(hit?._highlightResult?.title?.value || hit?.comment_text || '').replace(/<[^>]+>/g, ' ').trim(),
    }));
  }
} catch (error) {
  rawItems = [];
  securityStats.fetch_error = String(error?.message ?? 'fetch_failed').slice(0, 180);
}

securityStats.input_count = rawItems.length;
let items = rawItems
  .map((entry, idx) => sanitizeCandidate(entry, `item-${idx + 1}`))
  .filter((entry) => entry)
  .slice(0, 12);
securityStats.kept_count = items.length;

if (items.length === 0) {
  items = [
    {
      title: `${tier} trend heartbeat`,
      url: "https://news.ycombinator.com",
      snippet: 'No safe external feed data collected. Sending heartbeat event for monitoring continuity.',
      bucket: 'MONITOR',
      publisher: inferMeta("https://news.ycombinator.com").publisher,
      domain: inferMeta("https://news.ycombinator.com").domain,
      category: inferMeta("https://news.ycombinator.com").category,
      priorityTier: tier,
    },
  ];
}

return [
  {
    json: {
      query,
      collected_at: collectedAt,
      items,
      schedule_slot: scheduleSlot,
      priority_tier: tier,
      cadence,
      source_plan: { tier, cadence, domains: tierDomains },
      security_stats: securityStats,
    },
  },
];

const collectedAt = new Date().toISOString();
const dateKey = collectedAt.slice(0, 10);
const tier = 'P1';
const cadence = 'every_2_days';
const scheduleSlot = 'p1_every2days_kst_0910';
const queryBase = "P1 Signals: Engineering Depth + Product Strategy";
const tierDomains = ["techblog.woowahan.com", "daangn.com", "karrot.com", "blog.myrealtrip.com", "tech.socarcorp.kr", "upstage.ai", "blog.ab180.co", "netflixtechblog.com", "airbnb.tech", "uber.com", "huggingface.co", "deepmind.google", "stratechery.com", "lennysnewsletter.com"];
