const sanitizeText = (value, maxLen) => {
  let text = String(value ?? '');
  for (const pattern of INJECTION_PATTERNS) {
    const before = text;
    text = text.replace(pattern, ' ');
    if (before !== text) {
      securityStats.prompt_like_removed += 1;
    }
  }
  const normalized = compact(text);
  return normalized.length > maxLen ? `${normalized.slice(0, maxLen - 1).trimEnd()}…` : normalized;
};

const isSafeUrl = (value) => {
  const raw = String(value ?? '').trim();
  if (!/^https?:\/\//i.test(raw)) {
    return false;
  }
  const withoutScheme = raw.replace(/^https?:\/\//i, '');
  const authority = withoutScheme.split('/')[0] || '';
  const hostPort = authority.includes('@') ? authority.split('@').pop() : authority;
  const host = String((hostPort || '').split(':')[0] || '').toLowerCase();
  if (!host || host === 'localhost' || host.endsWith('.local')) {
    return false;
  }
  if (/^127\./.test(host) || /^10\./.test(host) || /^192\.168\./.test(host)) {
    return false;
  }
  if (/^172\.(1[6-9]|2\d|3[0-1])\./.test(host)) {
    return false;
  }
  if (/^169\.254\./.test(host) || host === '::1') {
    return false;
  }
  return true;
};

